    async function loadRole() {
      if (!supabase) {
        return;
      }

      const state = await getCurrentRole(supabase);

      if (!mounted) {
        return;
      }

      setSignedIn(Boolean(state.user));
      setRole(state.role);
    }

    loadRole();

    const { data: listener } = supabase?.auth.onAuthStateChange(() => {
      loadRole();
    }) ?? { data: null };

    return () => {
      mounted = false;
      listener?.subscription.unsubscribe();
    };
  }, [supabase]);

