export function buildReferralUrl(path: string, referralCode: string) {
  const appUrl = process.env.NEXT_PUBLIC_APP_URL || "http://localhost:3000";
  return `${appUrl}${path}?ref=${encodeURIComponent(referralCode)}`;
}

export function buildTelegramUrl(eventSlug: string, referralCode?: string | null) {
  const baseUrl = process.env.NEXT_PUBLIC_TELEGRAM_BOT_URL || "https://t.me/RaveeraBot";
  const payload = referralCode
    ? `event_${eventSlug}_ref_${referralCode}`
    : `event_${eventSlug}`;

  return `${baseUrl}?start=${encodeURIComponent(payload)}`;
}

export function slugify(value: string) {
  return value
    .toLowerCase()
    .trim()
    .replace(/['"]/g, "")
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
}

export function formatEventDate(date: string) {
  return new Intl.DateTimeFormat("en", {
    month: "short",
    day: "numeric",
    year: "numeric"
  }).format(new Date(date));
}

export function formatPrice(price: number, currency: string) {
  return `${new Intl.NumberFormat("en-US").format(price)} ${currency}`;
}

export function getCapacityPercent(registered: number, capacity: number) {
  return Math.min(Math.round((registered / capacity) * 100), 100);
}

