export const FALLBACK_EVENT_IMAGE = "/placeholder.jpg";

export function getSafeImageSrc(value: string | null | undefined) {
  if (typeof value !== "string" || !value.trim()) {
    return FALLBACK_EVENT_IMAGE;
  }

  const candidate = value.trim();

  if (candidate.startsWith("/")) {
    return candidate;
  }

  try {
    const url = new URL(candidate);
    return url.protocol === "https:" ? candidate : FALLBACK_EVENT_IMAGE;
  } catch {
    return FALLBACK_EVENT_IMAGE;
  }
}

"use client";

import Image from "next/image";
import { useEffect, useState } from "react";
import { FALLBACK_EVENT_IMAGE, getSafeImageSrc } from "@/lib/images";

type SafeEventImageProps = {
  src: string | null | undefined;
  alt: string;
  className: string;
  sizes: string;
  priority?: boolean;
};

export function SafeEventImage({ src, alt, className, sizes, priority = false }: SafeEventImageProps) {
  const [imageSrc, setImageSrc] = useState(getSafeImageSrc(src));

  useEffect(() => {
    setImageSrc(getSafeImageSrc(src));
  }, [src]);

  return (
    <Image
      src={imageSrc}
      alt={alt}
      fill
      priority={priority}
      className={className}
      sizes={sizes}
      onError={() => setImageSrc(FALLBACK_EVENT_IMAGE)}
    />
  );
}

