"use client";

import { useEffect, useMemo, useState, type FormEvent } from "react";
import { CheckCircle2, UserPlus } from "lucide-react";
import { getSupabaseBrowserClient } from "@/lib/supabase/client";

type EventRegistrationFormProps = {
  eventId: string;
};

type FormState = {
  name: string;
  email: string;
  telegramUsername: string;
};

const initialForm: FormState = {
  name: "",
  email: "",
  telegramUsername: ""
};

function isValidEmail(value: string) {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);
}

export function EventRegistrationForm({ eventId }: EventRegistrationFormProps) {
  const supabase = useMemo(() => getSupabaseBrowserClient(), []);
  const [open, setOpen] = useState(false);
  const [form, setForm] = useState<FormState>(initialForm);
  const [userId, setUserId] = useState<string | null>(null);
  const [authChecked, setAuthChecked] = useState(false);
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState<{ type: "success" | "error"; text: string } | null>(null);

  useEffect(() => {
    let mounted = true;

    async function loadSession() {
      if (!supabase) {
        setAuthChecked(true);
        return;
      }

      const {
        data: { user }
      } = await supabase.auth.getUser();

      if (!mounted) {
        return;
      }

      setUserId(user?.id ?? null);
      setForm((current) => ({
        ...current,
        email: current.email || user?.email || ""
      }));
      setAuthChecked(true);
    }

    loadSession();

    const { data: listener } = supabase?.auth.onAuthStateChange((_event, session) => {
      setUserId(session?.user.id ?? null);
      setForm((current) => ({
        ...current,
        email: current.email || session?.user.email || ""
      }));
      setAuthChecked(true);
    }) ?? { data: null };

    return () => {
      mounted = false;
      listener?.subscription.unsubscribe();
    };
  }, [supabase]);

  function updateField(field: keyof FormState, value: string) {
    setForm((current) => ({ ...current, [field]: value }));
  }

  async function submitRegistration(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    setMessage(null);

    const name = form.name.trim();
    const email = form.email.trim();
    const telegramUsername = form.telegramUsername.trim();

    if (!eventId) {
      setMessage({ type: "error", text: "Event id is missing. Refresh this page and try again." });
      return;
    }

    if (!name) {
      setMessage({ type: "error", text: "Name is required." });
      return;
    }

    if (!email || !isValidEmail(email)) {
      setMessage({ type: "error", text: "Enter a valid email address." });
      return;
    }

    if (!supabase) {
      setMessage({ type: "error", text: "Supabase is not configured for registrations." });
      return;
    }

    if (!userId) {
      setMessage({
        type: "error",
        text: "Sign in before registering. Current RLS only allows registrations tied to your user account."
      });
      return;
    }

    setLoading(true);

    const { error } = await supabase
      .from("registrations")
      .insert({
        event_id: eventId,
        user_id: userId,
        name,
        email,
        telegram_username: telegramUsername || null,
        status: "pending"
      });

    setLoading(false);

    if (error) {
      setMessage({ type: "error", text: error.message });
      return;
    }

    setMessage({ type: "success", text: "Registration received. Check Telegram for confirmation." });
    setForm((current) => ({
      ...initialForm,
      email: current.email
    }));
  }

  return (
    <section className="group relative border border-[#00FF88]/20 bg-[#020202] p-5 shadow-[0_0_90px_rgba(0,255,136,0.07)]">
      <span className="absolute left-0 top-0 h-px w-full bg-[#00FF88]" aria-hidden="true" />
      <div className="flex items-start gap-3">
        <span className="flex h-11 w-11 shrink-0 items-center justify-center border border-[#00FF88]/30 bg-[#030303] text-[#00FF88]">
          <UserPlus className="h-5 w-5" aria-hidden="true" />
        </span>
        <div>
          <p className="font-mono text-[10px] uppercase tracking-[0.22em] text-[#00FF88]">Registration</p>
          <h2 className="mt-2 text-2xl font-black uppercase leading-none">Reserve access</h2>
          <p className="mt-2 text-sm leading-6 text-white/45">
            Submit your registration details. Telegram handles the confirmation flow after the request is received.
          </p>
        </div>
      </div>

      {!open ? (
        <button
          type="button"
          onClick={() => setOpen(true)}
          className="focus-ring mt-5 min-h-11 w-full bg-[#00FF88] px-5 py-2.5 font-mono text-[11px] font-bold uppercase tracking-widest text-black motion-safe:transition-[filter,transform,box-shadow] motion-safe:duration-500 motion-safe:ease-out hover:brightness-110 hover:shadow-[0_0_34px_rgba(0,255,136,0.16)] active:scale-[0.98]"
        >
          Register
        </button>
      ) : (
        <form onSubmit={submitRegistration} className="mt-5 grid gap-4">
          <label className="block">
            <span className="font-mono text-[10px] uppercase tracking-[0.18em] text-white/35">Name</span>
            <input
              type="text"
              value={form.name}
              onChange={(event) => updateField("name", event.target.value)}
              autoComplete="name"
              required
              className="mt-2 min-h-11 w-full border border-white/[0.08] bg-black px-3 text-sm text-white outline-none motion-safe:transition-colors motion-safe:duration-500 focus:border-[#00FF88]"
            />
          </label>
          <label className="block">
            <span className="font-mono text-[10px] uppercase tracking-[0.18em] text-white/35">Email</span>
            <input
              type="email"
              value={form.email}
              onChange={(event) => updateField("email", event.target.value)}
              autoComplete="email"
              required
              className="mt-2 min-h-11 w-full border border-white/[0.08] bg-black px-3 font-mono text-sm text-white outline-none motion-safe:transition-colors motion-safe:duration-500 focus:border-[#00FF88]"
            />
          </label>
          <label className="block">
            <span className="font-mono text-[10px] uppercase tracking-[0.18em] text-white/35">Telegram username</span>
            <input
              type="text"
              value={form.telegramUsername}
              onChange={(event) => updateField("telegramUsername", event.target.value)}
              placeholder="@username"
              autoComplete="username"
              className="mt-2 min-h-11 w-full border border-white/[0.08] bg-black px-3 font-mono text-sm text-white outline-none motion-safe:transition-colors motion-safe:duration-500 focus:border-[#00FF88]"
            />
          </label>

          {!userId && authChecked ? (
            <p className="border border-white/[0.05] bg-[#030303] px-3 py-2 text-xs leading-5 text-white/45">
              Sign in to submit. The database RLS policy only accepts registrations connected to the current user.
            </p>
          ) : null}

          {message ? (
            <div
              className={message.type === "success" ? "border border-[#00FF88]/30 bg-[#00FF88]/[0.04] p-4 text-sm text-[#00FF88]" : "border border-red-400/25 bg-red-400/[0.035] p-4 text-sm text-red-100"}
              aria-live="polite"
            >
              <div className="flex items-start gap-2">
                {message.type === "success" ? <CheckCircle2 className="mt-0.5 h-4 w-4 shrink-0" aria-hidden="true" /> : null}
                <span>{message.text}</span>
              </div>
            </div>
          ) : null}

          <button
            type="submit"
            disabled={loading}
            className="focus-ring min-h-11 bg-[#00FF88] px-5 py-2.5 font-mono text-[11px] font-bold uppercase tracking-widest text-black motion-safe:transition-[filter,transform,opacity] motion-safe:duration-500 hover:brightness-110 active:scale-[0.98] disabled:cursor-not-allowed disabled:opacity-45"
          >
            {loading ? "Submitting" : "Submit registration"}
          </button>
        </form>
      )}
    </section>
  );
}

